arguments.file_text:
@rendermode InteractiveServer

<div class="dropzone @(_isDragOver ? "dropzone-highlight" : "")"
     @ondragenter="HandleDragEnter"
     @ondragover="HandleDragOver"
     @ondragleave="HandleDragLeave"
     @ondrop="HandleDrop"
     ondragover="event.preventDefault()"
     ondrop="event.preventDefault()">
    <InputFile OnChange="OnInputFileChange" multiple hidden id="file-drop-input" />
    <p class="dropzone-text">Drag &amp; drop files here</p>
</div>

@if (_fileEntries.Count > 0)
{
    <ul class="file-list">
        @foreach (var entry in _fileEntries)
        {
            <li class="file-entry @(entry.IsError ? "file-error" : "")">
                @if (entry.IsError)
                {
                    <span class="file-info">
                        <strong>@entry.Info.Name</strong> &mdash; @FormatSize(entry.Info.Size) (@entry.Info.Type)
                        <span class="error-message">File exceeds 10 MB limit</span>
                    </span>
                }
                else
                {
                    <span class="file-info">
                        <strong>@entry.Info.Name</strong> &mdash; @FormatSize(entry.Info.Size) (@entry.Info.Type)
                    </span>
                }
                <button class="btn-remove" @onclick="() => RemoveFile(entry)">Remove</button>
            </li>
        }
    </ul>
}

@code {
    public record FileInfo(string Name, long Size, string Type);

    [Parameter]
    public EventCallback<List<FileInfo>> OnFilesChanged { get; set; }

    private bool _isDragOver;
    private readonly List<FileEntry> _fileEntries = new();

    private const long MaxFileSizeBytes = 10 * 1024 * 1024;

    private record FileEntry(FileInfo Info, bool IsError);

    private void HandleDragEnter() => _isDragOver = true;
    private void HandleDragOver() => _isDragOver = true;
    private void HandleDragLeave() => _isDragOver = false;

    private async Task HandleDrop(DragEventArgs e)
    {
        _isDragOver = false;
        // Drop is handled via InputFile's OnChange since DragEventArgs doesn't carry file data in Blazor.
        // The actual file handling occurs through the InputFile component.
    }

    private async Task OnInputFileChange(InputFileChangeEventArgs e)
    {
        foreach (var file in e.GetMultipleFiles(maximumFileCount: 100))
        {
            var info = new FileInfo(file.Name, file.Size, file.ContentType);
            var isError = file.Size > MaxFileSizeBytes;
            _fileEntries.Add(new FileEntry(info, isError));
        }

        await NotifyParent();
    }

    private async Task RemoveFile(FileEntry entry)
    {
        _fileEntries.Remove(entry);
        await NotifyParent();
    }

    private async Task NotifyParent()
    {
        var accepted = _fileEntries
            .Where(e => !e.IsError)
            .Select(e => e.Info)
            .ToList();
        await OnFilesChanged.InvokeAsync(accepted);
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };
}

.dropzone {
    display: flex;
    align-items: center;
    justify-content: center;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 2rem;
    min-height: 150px;
    background-color: #f8f9fa;
    transition: background-color 0.2s, border-color 0.2s;
    cursor: pointer;
}

.dropzone-highlight {
    background-color: #d4edda;
    border-color: #28a745;
}

.dropzone-text {
    color: #6c757d;
    font-size: 1.1rem;
    margin: 0;
    pointer-events: none;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-info {
    display: flex;
    flex-direction: column;
    gap: 0.2rem;
}

.error-message {
    color: #dc3545;
    font-size: 0.85rem;
    font-weight: 600;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    cursor: pointer;
    font-size: 0.85rem;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

