.dropzone {
    display: flex;
    align-items: center;
    justify-content: center;
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 2rem;
    min-height: 150px;
    background-color: #f8f9fa;
    transition: background-color 0.2s, border-color 0.2s;
    cursor: pointer;
}

.dropzone-highlight {
    background-color: #d4edda;
    border-color: #28a745;
}

.dropzone-text {
    color: #6c757d;
    font-size: 1.1rem;
    margin: 0;
    pointer-events: none;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-info {
    display: flex;
    flex-direction: column;
    gap: 0.2rem;
}

.error-message {
    color: #dc3545;
    font-size: 0.85rem;
    font-weight: 600;
}

.btn-remove {
    background: none;
    border: 1px solid #dc3545;
    color: #dc3545;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    cursor: pointer;
    font-size: 0.85rem;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

